import{_ as a,o as n,c as e,a2 as i}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"WSL2 NFS Rootfs 排查","description":"","frontmatter":{"title":"WSL2 NFS Rootfs 排查"},"headers":[],"relativePath":"notes/2026-06-08-wsl2-nfsroot-ganesha-troubleshoot.md","filePath":"notes/2026-06-08-wsl2-nfsroot-ganesha-troubleshoot.md","lastUpdated":1781369075000}'),p={name:"notes/2026-06-08-wsl2-nfsroot-ganesha-troubleshoot.md"};function l(t,s,r,o,h,c){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="_2026-06-08-wsl2-nfs-rootfs-troubleshooting-note" tabindex="-1">2026-06-08 WSL2 NFS Rootfs Troubleshooting Note <a class="header-anchor" href="#_2026-06-08-wsl2-nfs-rootfs-troubleshooting-note" aria-label="Permalink to &quot;2026-06-08 WSL2 NFS Rootfs Troubleshooting Note&quot;">​</a></h1><h2 id="symptom" tabindex="-1">Symptom <a class="header-anchor" href="#symptom" aria-label="Permalink to &quot;Symptom&quot;">​</a></h2><p>The i.MX6ULL board booted a new Linux 7.0 kernel with NFS rootfs bootargs:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>console=ttymxc0,115200 root=/dev/nfs rw nfsroot=192.168.60.1:/home/charliechen/imx-forge/rootfs/nfs,v3,tcp ip=192.168.60.200:192.168.60.1:192.168.60.1:255.255.255.0::eth0:off</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The kernel brought up Ethernet and completed static IP configuration:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fec 20b4000.ethernet eth0: Link is Up - 100Mbps/Full - flow control rx/tx</span></span>
<span class="line"><span>IP-Config: Complete:</span></span>
<span class="line"><span>     device=eth0, hwaddr=b8:ae:1d:01:00:04, ipaddr=192.168.60.200, mask=255.255.255.0, gw=192.168.60.1</span></span>
<span class="line"><span>     bootserver=192.168.60.1, rootserver=192.168.60.1, rootpath=</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>But the board did not mount the NFS rootfs. Packet capture did not show the expected NFS mount traffic from the board.</p><h2 id="important-lesson" tabindex="-1">Important Lesson <a class="header-anchor" href="#important-lesson" aria-label="Permalink to &quot;Important Lesson&quot;">​</a></h2><p>Do not start by blaming the board, bootargs, firewall, or kernel config when the host-side NFS server changed.</p><p>First prove the host can mount its own export locally:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/nfs-test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vers=3,proto=tcp,nolock</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  127.0.0.1:/home/charliechen/imx-forge/rootfs/nfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/nfs-test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>In this case, localhost NFSv3 mount also hung. That immediately moved the fault boundary from board/kernel to WSL2 NFS service.</p><h2 id="failed-kernel-nfs-server-evidence" tabindex="-1">Failed Kernel NFS Server Evidence <a class="header-anchor" href="#failed-kernel-nfs-server-evidence" aria-label="Permalink to &quot;Failed Kernel NFS Server Evidence&quot;">​</a></h2><p><code>nfs-kernel-server</code> appeared superficially alive:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exportfs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rav</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exportfs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpcinfo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">showmount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>But actual NFSv3 mount hung around the MOUNT/NFS RPC flow:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mount.nfs: prog 100003, trying vers=3, prot=6</span></span>
<span class="line"><span>mount.nfs: trying 127.0.0.1 prog 100003 vers 3 prot TCP port 2049</span></span>
<span class="line"><span>mount.nfs: prog 100005, trying vers=3, prot=6</span></span>
<span class="line"><span>mount.nfs: trying 127.0.0.1 prog 100005 vers 3 prot TCP port &lt;random&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The kernel nfsd export table was also empty even after <code>exportfs -rav</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/fs/nfsd/threads</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 8</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/fs/nfsd/exports</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Version 1.1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Path Client(Flags) # IPs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>A minimal <code>/srv/nfs-test</code> export had the same failure, so the problem was not the rootfs directory.</p><p>Conclusion: this new WSL2 environment&#39;s kernel NFS server path was unusable for NFSv3 rootfs boot.</p><h2 id="working-fix-nfs-ganesha" tabindex="-1">Working Fix: NFS-Ganesha <a class="header-anchor" href="#working-fix-nfs-ganesha" aria-label="Permalink to &quot;Working Fix: NFS-Ganesha&quot;">​</a></h2><p>Install Ganesha and the VFS FSAL plugin:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-ganesha</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-ganesha-vfs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Stop the kernel NFS server but keep <code>rpcbind</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-kernel-server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rpcbind</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Use this <code>/etc/ganesha/ganesha.conf</code>:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NFS_CORE_PARAM {</span></span>
<span class="line"><span>    Protocols = 3;</span></span>
<span class="line"><span>    Bind_addr = 0.0.0.0;</span></span>
<span class="line"><span>    NFS_Port = 2049;</span></span>
<span class="line"><span>    MNT_Port = 20048;</span></span>
<span class="line"><span>    mount_path_pseudo = false;</span></span>
<span class="line"><span>    Enable_NLM = false;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>EXPORT_DEFAULTS {</span></span>
<span class="line"><span>    Access_Type = RW;</span></span>
<span class="line"><span>    Squash = no_root_squash;</span></span>
<span class="line"><span>    SecType = sys;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>EXPORT {</span></span>
<span class="line"><span>    Export_Id = 1;</span></span>
<span class="line"><span>    Path = /home/charliechen/imx-forge/rootfs/nfs;</span></span>
<span class="line"><span>    Pseudo = /nfsroot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Access_Type = RW;</span></span>
<span class="line"><span>    Squash = no_root_squash;</span></span>
<span class="line"><span>    SecType = sys;</span></span>
<span class="line"><span>    Protocols = 3;</span></span>
<span class="line"><span>    Transports = TCP;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    FSAL {</span></span>
<span class="line"><span>        Name = VFS;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    CLIENT {</span></span>
<span class="line"><span>        Clients = 127.0.0.1, 192.168.60.0/24;</span></span>
<span class="line"><span>        Access_Type = RW;</span></span>
<span class="line"><span>        Squash = no_root_squash;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>LOG {</span></span>
<span class="line"><span>    Default_Log_Level = INFO;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Facility {</span></span>
<span class="line"><span>        name = FILE;</span></span>
<span class="line"><span>        destination = &quot;/var/log/ganesha/ganesha.log&quot;;</span></span>
<span class="line"><span>        enable = active;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br></div></div><p>Restart and verify:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-ganesha</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpcinfo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">showmount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Expected key ports:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100003    3   tcp   2049  nfs</span></span>
<span class="line"><span>100005    3   tcp  20048  mountd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Expected export:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Export list for 127.0.0.1:</span></span>
<span class="line"><span>/home/charliechen/imx-forge/rootfs/nfs 127.0.0.1/32,192.168.60.0/24</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If <code>showmount</code> is empty, check <code>/var/log/ganesha/ganesha.log</code>. A common missing package error is:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to load FSAL (VFS) because: No such file or directory</span></span>
<span class="line"><span>No export entries found in configuration file !!!</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Fix it with:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-ganesha-vfs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-ganesha</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="final-working-u-boot-bootargs" tabindex="-1">Final Working U-Boot Bootargs <a class="header-anchor" href="#final-working-u-boot-bootargs" aria-label="Permalink to &quot;Final Working U-Boot Bootargs&quot;">​</a></h2><p>Direct <code>bootargs</code>:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv bootargs &#39;console=ttymxc0,115200 root=/dev/nfs rw nfsroot=192.168.60.1:/home/charliechen/imx-forge/rootfs/nfs,vers=3,proto=tcp,nolock,port=2049,mountport=20048 ip=192.168.60.200:192.168.60.1:192.168.60.1:255.255.255.0:imx6ull-aes:eth0:off&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Reusable U-Boot environment:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv ipaddr 192.168.60.200</span></span>
<span class="line"><span>setenv serverip 192.168.60.1</span></span>
<span class="line"><span>setenv gatewayip 192.168.60.1</span></span>
<span class="line"><span>setenv netmask 255.255.255.0</span></span>
<span class="line"><span>setenv hostname imx6ull-aes</span></span>
<span class="line"><span>setenv nfsrootdir /home/charliechen/imx-forge/rootfs/nfs</span></span>
<span class="line"><span>setenv nfsargs &#39;setenv bootargs console=ttymxc0,115200 root=/dev/nfs rw nfsroot=\${serverip}:\${nfsrootdir},vers=3,proto=tcp,nolock,port=2049,mountport=20048 ip=\${ipaddr}:\${serverip}:\${gatewayip}:\${netmask}:\${hostname}:eth0:off&#39;</span></span>
<span class="line"><span>setenv netbootaes &#39;run nfsargs; tftp \${loadaddr} \${bootfile}; tftp \${fdt_addr} \${fdt_file}; bootz \${loadaddr} - \${fdt_addr}&#39;</span></span>
<span class="line"><span>run netbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="why-mountport-20048-matters" tabindex="-1">Why <code>mountport=20048</code> Matters <a class="header-anchor" href="#why-mountport-20048-matters" aria-label="Permalink to &quot;Why \`mountport=20048\` Matters&quot;">​</a></h2><p>NFSv3 uses both:</p><ul><li>NFS service: RPC program <code>100003</code>, normally TCP port <code>2049</code>.</li><li>MOUNT service: RPC program <code>100005</code>, often a random dynamic port.</li></ul><p>Ganesha was configured with:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NFS_Port = 2049;</span></span>
<span class="line"><span>MNT_Port = 20048;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The kernel bootargs then pin both ports:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>port=2049,mountport=20048</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This avoids random mountd ports and makes WSL/Windows firewall or port-forwarding troubleshooting much less painful.</p><h2 id="debug-checklist" tabindex="-1">Debug Checklist <a class="header-anchor" href="#debug-checklist" aria-label="Permalink to &quot;Debug Checklist&quot;">​</a></h2><ol><li>Check that the board got IP:</li></ol><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IP-Config: Complete</span></span>
<span class="line"><span>device=eth0</span></span>
<span class="line"><span>rootserver=192.168.60.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ol start="2"><li>Check Ganesha exports:</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">showmount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpcinfo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="3"><li>Check Ganesha logs:</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -120</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/ganesha/ganesha.log</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="4"><li>If using NFSv3 rootfs, always include:</li></ol><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vers=3,proto=tcp,nolock,port=2049,mountport=20048</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="5"><li>If the board cannot reach it but localhost can, inspect Windows/WSL networking next.</li></ol>`,61)])])}const u=a(p,[["render",l]]);export{b as __pageData,u as default};
